mapper.select:
/* Payment.selectPaymentById */
SELECT

FROM TB_PAYMENT
WHERE ID = #{id}

/* Payment.selectPaymentByPaymentId */
SELECT

FROM TB_PAYMENT
WHERE PAYMENT_ID = #{paymentId}

/* Payment.selectPaymentByOrderNo */
SELECT

FROM TB_PAYMENT
WHERE ORDER_NO = #{orderNo}
ORDER BY ID DESC
LIMIT 1

/* Payment.selectPaymentDets */
SELECT

FROM TB_PAYMENT_DET
WHERE PAYMENT_ID = #{paymentId}
ORDER BY ID ASC
